// // This module implements a combinational logic circuit that outputs X based on the inputs A1, A2, A3, and B1. The output X is true (high) when either both A1 and A2 are false, or when A1 is true and both A3 and B1 are false, or when A1 is true, A3 is true, and both A2 and B1 are false.
module top_module(
    input  A1,
    input  A2,
    input  A3,
    input  B1,
    output X
);assign X = (A1 & A2) | (~A1 & A3 & B1) | (~A1 & ~A3 & (A2 & B1));

endmodule
